INSERT INTO organizations (id, name, description, category_id, raised, goal, donor_count, featured) VALUES
  ('org-blackgirls-code', 'Black Girls CODE', 'Introducing programming and technology to young girls of color through workshops, hackathons, and after-school programs.', 'cat-education', 45000.00, 100000.00, 312, true),
  ('org-naacp-ldf', 'NAACP Legal Defense Fund', 'Fighting for racial justice through litigation, advocacy, and public education to advance the cause of equality.', 'cat-civil-rights', 78500.00, 150000.00, 523, true),
  ('org-uncf', 'United Negro College Fund', 'Supporting students and HBCUs with scholarships, internships, and mentoring for academic success.', 'cat-education', 125000.00, 250000.00, 892, true),
  ('org-national-urban', 'National Urban League', 'Empowering communities through education, jobs, housing, and health programs in underserved areas.', 'cat-community', 62000.00, 120000.00, 445, false),
  ('org-black-health', 'Black Health Alliance', 'Improving the health and well-being of Black communities through research, education, and policy advocacy.', 'cat-health', 34500.00, 80000.00, 201, false),
  ('org-harlem-arts', 'Harlem Arts Alliance', 'Promoting and preserving Black arts, culture, and creative expression through exhibitions, performances, and grants.', 'cat-arts', 28000.00, 60000.00, 167, false),
