INSERT INTO campaigns (id, organization_id, title, description, story, about, location, goal, raised, donor_count, status) VALUES
  ('camp-bgc-2024', 'org-blackgirls-code', 'Summer Tech Camp 2024',
   'Send 500 girls to summer tech camp with hands-on coding workshops.',
   'Every summer, Black Girls CODE brings together hundreds of young girls from underserved communities to learn programming, robotics, and web development. Our Summer Tech Camp 2024 aims to reach 500 girls across 10 cities, providing them with the tools and mentorship they need to pursue careers in technology. Your donation helps cover equipment, venue costs, instructor fees, and scholarships for families who cannot afford camp registration.',
   'Black Girls CODE is devoted to showing the world that girls of every color have the skills to become the programmers of tomorrow. By reaching out to teach girls of color ages 7-17 the skills to build and create their own apps, robots, and games, we hope to grow the number of women of color working in technology.',
   'United States', 50000.00, 23000.00, 156, 'active'),
  ('camp-naacp-justice', 'org-naacp-ldf', 'Justice for All Campaign',
   'Support ongoing civil rights litigation and advocacy efforts across the nation.',
   'The NAACP Legal Defense Fund has been at the forefront of civil rights litigation for over 80 years. Our Justice for All Campaign supports critical legal battles against voter suppression, police misconduct, and systemic discrimination. Every dollar goes directly to funding legal teams, filing briefs, and supporting communities seeking justice through the courts.',
   'The NAACP Legal Defense and Educational Fund is the premier legal organization fighting for racial justice. Through litigation, advocacy, and public education, LDF seeks structural changes to expand democracy, eliminate disparities, and achieve racial justice.',
   'United States', 100000.00, 52000.00, 287, 'active'),
  ('camp-uncf-scholarships', 'org-uncf', 'HBCU Scholarship Drive',
   'Fund 200 new scholarships for students attending HBCUs this academic year.',
   'Historically Black Colleges and Universities have been the backbone of Black higher education for over 150 years. Our HBCU Scholarship Drive aims to fund 200 new scholarships, helping students who might otherwise be unable to afford tuition. Each scholarship covers books, housing, and partial tuition, making the dream of a college education accessible to more students from underrepresented communities.',
   'UNCF (United Negro College Fund) is the largest and most effective minority education organization in the country. UNCF supports students education and development through scholarships and other programs, supports and strengthens its 37 member colleges and universities, and advocates for the importance of minority education.',
   'United States', 150000.00, 85000.00, 412, 'active'),
  ('camp-urban-jobs', 'org-national-urban', 'Jobs & Skills Initiative',
   'Train 1,000 community members in high-demand digital skills.',
   'The digital economy is growing rapidly, but many communities are being left behind. Our Jobs & Skills Initiative provides free training in web development, data analytics, cybersecurity, and digital marketing to 1,000 community members. Participants receive mentorship, job placement assistance, and industry-recognized certifications to help them secure well-paying careers in the tech sector.',
   'The National Urban League is a historic civil rights organization dedicated to economic empowerment, equality, and social justice. Through direct services and advocacy, the Urban League helps African Americans and others secure economic self-reliance, parity, power, and civil rights.',
   'United States', 75000.00, 38000.00, 198, 'active'),
  ('camp-health-screening', 'org-black-health', 'Community Health Screenings',
   'Free health screenings and wellness workshops in 20 cities.',
   'Health disparities continue to disproportionately affect Black communities across the country. Our Community Health Screenings campaign brings free medical screenings for diabetes, hypertension, cholesterol, and mental health assessments to 20 cities. Each event includes wellness workshops, nutrition counseling, and referrals to local healthcare providers for follow-up care.',
   'The Black Health Alliance works to improve the health and well-being of Black communities through culturally-informed research, education, and policy advocacy. We believe health equity is a fundamental right and work to eliminate barriers to quality healthcare.',
   'United States', 40000.00, 15000.00, 89, 'active'),
  ('camp-arts-festival', 'org-harlem-arts', 'Black Arts Festival 2024',
   'Annual celebration of Black creativity featuring over 100 artists.',
   'The Black Arts Festival is an annual celebration of African American artistic excellence. This year, we are bringing together over 100 visual artists, musicians, poets, dancers, and filmmakers for a weekend of performances, exhibitions, and workshops. Your support helps cover artist stipends, venue rental, equipment, and community outreach to ensure the festival remains free and accessible to all.',
   'The Harlem Arts Alliance promotes and preserves Black arts, culture, and creative expression. Through exhibitions, performances, grants, and community programs, we nurture artistic talent and celebrate the rich cultural heritage of the African diaspora.',
   'United States', 30000.00, 12000.00, 78, 'active'),
  ('camp-youth-leaders', 'org-youth-build', 'Youth Leadership Academy',
   'Year-long leadership development program for 150 young people.',
   'The Youth Leadership Academy is a comprehensive year-long program that transforms young people from low-income communities into confident leaders. Participants receive mentorship from industry professionals, hands-on project management experience, public speaking training, and college preparation support. Graduates leave with the skills and confidence to pursue higher education and meaningful careers.',
   'YouthBuild USA helps young people who have been failed by their school systems get back on track. Through construction training, GED preparation, leadership development, and community service, YouthBuild participants gain the education and skills they need to achieve economic self-sufficiency.',
   'United States', 60000.00, 32000.00, 167, 'active'),
  ('camp-green-gardens', 'org-green-roots', 'Community Gardens Project',
   'Create 10 urban community gardens in food desert neighborhoods.',
   'Food deserts affect millions of people in urban communities, limiting access to fresh, healthy food. Our Community Gardens Project creates 10 new urban gardens in food desert neighborhoods, providing fresh produce, gardening education, and green community spaces. Each garden includes raised beds, irrigation systems, tool sheds, and composting facilities, designed to be self-sustaining for years to come.',
   'Green Roots Initiative brings environmental justice and sustainability programs to Black and brown communities. We believe that everyone deserves access to clean air, clean water, healthy food, and green spaces, regardless of their zip code.',
   'United States', 25000.00, 9500.00, 62, 'active')
ON CONFLICT (id) DO NOTHING;
